use std::io::stdin;

fn read_line() -> String {
    let mut buf = String::new();
    stdin().read_line(&mut buf).expect("Failed to read a line");
    buf
}

pub fn main() {
    let line = read_line();
    let mut iter = line.trim().split_whitespace().map(|x| x.parse::<i64>().unwrap());
    let w = iter.next().unwrap();
    let h = iter.next().unwrap();
    let mut result: u64 = 1;
    for _ in 0..w + h {
        result *= 2;
        result %= 998244353;
    }
    println!("{}", result);
}
